#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main(void)
{
    int a, b, c, i, ans = 0;
    scanf("%d%d", &a, &b);
    c = a - b;
    if (c == 0)
    {
        printf("infinity");
        return 0;
    }

    for (i = 1; i * i <= c; i++)
    {
        if (c % i == 0)
        {
            if (i > b)
                ans++;
            if ((c / i != i) && (c / i > b))
                ans++;
        }
    }

    printf("%d", ans);
    return 0;
}

