use std::io;
use std::str;

pub struct Scanner<R> {
    reader: R,
    buffer: Vec<String>,
}

impl<R: io::BufRead> Scanner<R> {
    pub fn new(reader: R) -> Self {
        Self {
            reader,
            buffer: vec![],
        }
    }

    pub fn token<T: str::FromStr>(&mut self) -> T {
        loop {
            if let Some(token) = self.buffer.pop() {
                return token.parse().ok().expect("Failed parse");
            }
            let mut input = String::new();
            self.reader.read_line(&mut input).expect("Failed read");
            self.buffer = input.split_whitespace().rev().map(String::from).collect();
        }
    }
}

fn get_divisors(n: u64) -> Vec<u64> {
    let mut ans = vec![1];
    if n > 1 {
        ans.push(n);
    }
    let mut d = 2;
    while d * d <= n {
        if n % d == 0 {
            ans.push(d);
            if d * d < n {
                ans.push(n / d);
            }
        }
        d += 1;
    }
    ans.sort();
    ans
}

fn upper_bound(arr: &[u64], target: u64) -> usize {
    let mut lo = 0;
    let mut hi = arr.len();
    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        if arr[mid] > target {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    lo
}

fn solve<R: io::BufRead, W: io::Write>(scan: &mut Scanner<R>, out: &mut W) {
    let a: u64 = scan.token();
    let b: u64 = scan.token();
    if a == 0 {
        if b == 0 {
            writeln!(out, "infinity").ok();
        } else {
            writeln!(out, "0").ok();
        }
    } else {
        if a < b {
            writeln!(out, "0").ok();
        } else if a == b {
            writeln!(out, "infinity").ok();
        } else {
            // Solve the modular equation a ≡ b (mod x).
            // a = x * k + b, where k is some integer.
            // (a - b) = x * k -> x is a divisor of (a - b)
            // Count divisors of (a - b) such that x > b.
            let divisors = get_divisors(a - b);
            let ub = upper_bound(&divisors, b);
            let ans = divisors.len() - ub;
            writeln!(out, "{}", ans).ok();
        }
    }
}

fn main() {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = Scanner::new(stdin.lock());
    let mut out = io::BufWriter::new(stdout.lock());
    solve(&mut scan, &mut out);
}
